import { NextResponse } from "next/server";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/lib/auth";
import { extractText } from "unpdf";
const pdfParse = require("pdf-parse");

export async function POST(req: Request) {
  try {
    const session = await getServerSession(authOptions);
    const userId = (session?.user as any)?.id;
    if (!userId) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const formData = await req.formData();
    const file = formData.get("file") as File | null;

    if (!file) {
      return NextResponse.json({ error: "No PDF file provided" }, { status: 400 });
    }

    const arrayBuffer = await file.arrayBuffer();
    const buffer = Buffer.from(arrayBuffer);

    let textStr = "";

    try {
      const { text } = await extractText(new Uint8Array(arrayBuffer));
      textStr = Array.isArray(text) ? text.join('\n') : text;
    } catch (unpdfError) {
      console.warn("unpdf failed, trying pdf-parse fallback", unpdfError);
      try {
        const data = await pdfParse(buffer);
        textStr = data.text;
      } catch (pdfParseError) {
        throw new Error("Both PDF engines failed to extract text.");
      }
    }

    if (!textStr || textStr.trim().length === 0) {
      return NextResponse.json({ error: "No text could be extracted from PDF" }, { status: 400 });
    }

    return NextResponse.json({ code: textStr.trim() });
  } catch (error: any) {
    console.error("PDF Parsing error:", error);
    return NextResponse.json({ error: error.message || "Failed to process PDF" }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from "next/server"
import { generateAIResponse } from "@/lib/ai"
import { prisma } from "@/lib/prisma"
import { getServerSession } from "next-auth"
import { authOptions } from "@/lib/auth"

export async function POST(req: NextRequest) {
  const session = await getServerSession(authOptions)

  if (!session?.user?.email) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 })
  }

  const { code } = await req.json()

  const prompt = `Review this code:\n${code}`

  try {
    const result = await generateAIResponse(prompt)

    const user = await prisma.user.findUnique({
      where: { email: session.user.email },
    })

    if (user) {
      await prisma.analysis.create({
        data: {
          userId: user.id,
          input: code,
          result: result || "No response received",
        },
      })
    }

    return NextResponse.json({ result: result || "Review failed" })
  } catch (error: any) {
    console.error("API REVIEW ERROR:", error)
    return NextResponse.json({ 
      error: error.message || "Unknown server error during analysis/storage." 
    }, { status: 500 })
  }
}

"use client";

import { useState, useRef } from "react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import Editor from "@monaco-editor/react";
import { GitBranch, Code, Play, FileText, Upload } from "lucide-react";
import { useSession } from "next-auth/react";

export default function InputSection({ onAnalyze }: { onAnalyze: (type: string, payload: string) => void }) {
  const [activeTab, setActiveTab] = useState("code");
  const [code, setCode] = useState("// Paste your code here\n");
  const [language, setLanguage] = useState("typescript");
  const [githubUrl, setGithubUrl] = useState("");
  const [pdfFile, setPdfFile] = useState<File | null>(null);
  const [loading, setLoading] = useState(false);
  const { data: session } = useSession();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleAnalyze = async () => {
    if (!session) {
      alert("Please login to analyze code.");
      return;
    }

    setLoading(true);
    try {
      if (activeTab === "code" && code.trim()) {
        await onAnalyze("code", `Language Context: ${language}\n\n${code}`);
      } else if (activeTab === "github" && githubUrl.trim()) {
        const res = await fetch("/api/github", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ url: githubUrl })
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error);
        await onAnalyze("github", `Language Context: ${language}\n\n${data.code}`);
      } else if (activeTab === "pdf" && pdfFile) {
        const formData = new FormData();
        formData.append("file", pdfFile);
        const res = await fetch("/api/pdf", {
          method: "POST",
          body: formData
        });
        const data = await res.json();
        if (!res.ok) throw new Error(data.error);
        await onAnalyze("pdf", `Language Context: ${language}\n\n${data.code}`);
      }
    } catch (err: any) {
      alert(`Processing Error: ${err.message}`);
    } finally {
      setLoading(false);
    }
  };

  const isDisabled = 
    loading || 
    (activeTab === "code" ? code.trim() === "" : false) ||
    (activeTab === "github" ? githubUrl.trim() === "" : false) ||
    (activeTab === "pdf" ? pdfFile === null : false) ||
    !session;

  return (
    <div className="w-full max-w-4xl mx-auto mt-8 border border-border rounded-xl bg-card overflow-hidden shadow-lg">
      <Tabs defaultValue="code" onValueChange={setActiveTab} className="w-full">
        <div className="flex items-center justify-between p-4 border-b border-border bg-background/50">
          <TabsList className="bg-secondary/50">
            <TabsTrigger value="code" className="gap-2">
              <Code className="w-4 h-4" /> Code
            </TabsTrigger>
            <TabsTrigger value="github" className="gap-2">
              <GitBranch className="w-4 h-4" /> GitHub
            </TabsTrigger>
            <TabsTrigger value="pdf" className="gap-2">
              <FileText className="w-4 h-4" /> PDF
            </TabsTrigger>
          </TabsList>

          <Button 
            onClick={handleAnalyze} 
            disabled={isDisabled}
            className="bg-primary text-primary-foreground hover:bg-primary/90 font-semibold gap-2 transition-all"
          >
            {loading ? (
              <div className="w-4 h-4 border-2 border-primary-foreground border-t-transparent rounded-full animate-spin" />
            ) : (
              <Play className="w-4 h-4 fill-current" />
            )}
            {loading ? "Analyzing..." : "Analyze"}
          </Button>
        </div>

        <TabsContent value="code" className="m-0 focus-visible:outline-none">
          <div className="flex items-center justify-between px-4 py-2 border-t border-border bg-muted/20">
            <span className="text-sm font-medium text-muted-foreground mr-3">Language</span>
            <select
              value={language}
              onChange={(e) => setLanguage(e.target.value)}
              className="bg-background border border-border text-foreground text-sm rounded-md px-3 py-1.5 focus:outline-none focus:ring-2 focus:ring-primary/50 w-[160px] shadow-sm transition-colors"
            >
              <option value="typescript">TypeScript</option>
              <option value="javascript">JavaScript</option>
              <option value="python">Python</option>
              <option value="java">Java</option>
              <option value="c">C</option>
              <option value="cpp">C++</option>
              <option value="csharp">C#</option>
              <option value="go">Go</option>
              <option value="rust">Rust</option>
              <option value="php">PHP</option>
              <option value="ruby">Ruby</option>
              <option value="swift">Swift</option>
              <option value="kotlin">Kotlin</option>
              <option value="html">HTML</option>
              <option value="css">CSS</option>
              <option value="json">JSON</option>
              <option value="sql">SQL</option>
              <option value="markdown">Markdown</option>
            </select>
          </div>
          <div className="h-[360px] w-full border-t border-border">
            <Editor
              height="100%"
              theme="vs-dark"
              language={language}
              value={code}
              onChange={(val) => setCode(val || "")}
              options={{
                minimap: { enabled: false },
                fontSize: 14,
                padding: { top: 16 },
                scrollBeyondLastLine: false,
              }}
            />
          </div>
        </TabsContent>

        <TabsContent value="github" className="m-0 focus-visible:outline-none p-8 h-[400px]">
          <div className="max-w-xl mx-auto space-y-4 pt-12">
            <h3 className="text-lg font-medium text-foreground text-center">
              Analyze a GitHub Repository
            </h3>
            <p className="text-sm text-muted-foreground text-center">
              Paste the URL of a public GitHub repository. We will fetch and analyze the codebase.
            </p>
            <div className="relative pt-4">
              <GitBranch className="absolute left-3 top-7 w-5 h-5 text-muted-foreground" />
              <Input 
                placeholder="https://github.com/user/repo" 
                className="pl-10 h-12 bg-background border-border"
                value={githubUrl}
                onChange={(e) => setGithubUrl(e.target.value)}
              />
            </div>
          </div>
        </TabsContent>

        <TabsContent value="pdf" className="m-0 focus-visible:outline-none p-8 h-[400px]">
          <div className="max-w-xl mx-auto space-y-4 pt-12">
            <h3 className="text-lg font-medium text-foreground text-center">
              Upload PDF Code Document
            </h3>
            <p className="text-sm text-muted-foreground text-center">
              Upload a document with code. We will extract all readable text for analysis.
            </p>
            <div className="pt-4 flex flex-col items-center gap-4">
              <input 
                type="file" 
                accept="application/pdf" 
                className="hidden" 
                ref={fileInputRef}
                onChange={(e) => setPdfFile(e.target.files?.[0] || null)}
              />
              <Button 
                variant="outline" 
                className="gap-2 w-full h-12 border-dashed border-2"
                onClick={() => fileInputRef.current?.click()}
              >
                <Upload className="w-4 h-4" />
                {pdfFile ? pdfFile.name : "Select PDF Document"}
              </Button>
            </div>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

"use client";

import { motion } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Separator } from "@/components/ui/separator";
import Editor from "@monaco-editor/react";
import { CheckCircle, AlertTriangle, Info, Terminal, FileText, Activity } from "lucide-react";

type Bug = {
  type: string;
  severity: "Critical" | "Warning" | "Info";
  message: string;
};

type Metrics = {
  complexity: string;
  readability: string;
  maintainability: string;
};

export type AnalysisResult = {
  score: number;
  summary: string;
  bugs: Bug[];
  suggestions: string[];
  refactored_code: string;
  documentation: string;
  metrics: Metrics;
};

const containerVariants = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: { staggerChildren: 0.1 }
  }
};

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  show: { opacity: 1, y: 0 }
};

export default function ResultsDisplay({ result }: { result: AnalysisResult }) {
  if (!result) return null;

  return (
    <motion.div 
      variants={containerVariants}
      initial="hidden"
      animate="show"
      className="w-full max-w-4xl mx-auto mt-8 space-y-6"
    >
      {/* Score and Summary */}
      <motion.div variants={itemVariants} className="grid md:grid-cols-3 gap-6">
        <Card className="col-span-1 border-primary/20 bg-card hover:border-primary/50 transition-colors">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <Activity className="w-4 h-4 text-primary" />
              Quality Score
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-5xl font-bold text-foreground">
              {result.score}<span className="text-2xl text-muted-foreground">/10</span>
            </div>
          </CardContent>
        </Card>

        <Card className="col-span-2 border-border bg-card">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium text-muted-foreground flex items-center gap-2">
              <Info className="w-4 h-4 text-primary" />
              Summary
            </CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-foreground leading-relaxed">
              {result.summary}
            </p>
          </CardContent>
        </Card>
      </motion.div>

      {/* Metrics */}
      {result.metrics && (
        <motion.div variants={itemVariants} className="grid grid-cols-3 gap-4">
          {[
            { label: "Complexity", val: result.metrics?.complexity ?? "N/A" },
            { label: "Readability", val: result.metrics?.readability ?? "N/A" },
            { label: "Maintainability", val: result.metrics?.maintainability ?? "N/A" }
          ].map(m => (
            <Card key={m.label} className="border-border bg-card">
              <CardContent className="p-4 flex flex-col justify-center items-center text-center">
                <h4 className="text-xs text-muted-foreground uppercase tracking-wider">{m.label}</h4>
                <p className="text-sm sm:text-base font-semibold text-foreground mt-1">{m.val}</p>
              </CardContent>
            </Card>
          ))}
        </motion.div>
      )}

      {/* Bugs */}
      {result.bugs && result.bugs.length > 0 && (
        <motion.div variants={itemVariants}>
          <Card className="border-border bg-card">
            <CardHeader>
              <CardTitle className="text-lg flex items-center gap-2">
                <AlertTriangle className="w-5 h-5 text-destructive" />
                Detected Issues
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {result.bugs.map((bug, idx) => (
                <div key={idx} className="flex flex-col sm:flex-row gap-3 items-start p-3 rounded-lg bg-background/50 border border-border">
                  <Badge variant={bug.severity === "Critical" ? "destructive" : "secondary"} className="mt-0.5">
                    {bug.severity}
                  </Badge>
                  <div>
                    <h5 className="font-semibold text-foreground text-sm">{bug.type}</h5>
                    <p className="text-muted-foreground text-sm">{bug.message}</p>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
        </motion.div>
      )}

      {/* Suggestions */}
      {result.suggestions && result.suggestions.length > 0 && (
        <motion.div variants={itemVariants}>
          <Card className="border-border bg-card">
            <CardHeader>
              <CardTitle className="text-lg flex items-center gap-2">
                <CheckCircle className="w-5 h-5 text-primary" />
